var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"저 사람의 이름은 라비. 당신의 아버지입니다.","JPN":"あの人の名前はラビ。あなたの父親です。","ENG":"That person's name is Ravi. He is your father.","TWN":"那個人的名字是拉維，他就是你的爸爸。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"라비…… 아버지…….","JPN":"ラビ……お父さん……","ENG":"Ravi... My father...","TWN":"拉維……我的爸爸……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지의 기억이 여기 투영되었다는 것은…… 아버지 역시…….","JPN":"お父さんの記憶がここに投影されたということは……お父さんも……","ENG":"Seeing a projection of my father's memory here... can only mean that...","TWN":"爸爸的記憶被投影在這裡……那爸爸他也……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 역겨운 잔재주를 이용해 잘도 모습을 숨기고 계셨군요. 찾느라 고생 좀 했습니다.","JPN":"そのむかつく小細工でよくも姿を暗ましていましたね。探すのに苦労しました。","ENG":"So you have been using that vile trick to hide from us. It took us quite the trouble to find you.","TWN":"可真夠會躲的，多虧了你那些噁心的小把戲，我找你們可費了不少功夫。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"역시…… 들켜버렸네요.","JPN":"やはり……バレてしまいましたか。","ENG":"So... we've been caught.","TWN":"果然……還是被發現了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아, 아버지…….","JPN":"お、お父さん……","ENG":"F-father...","TWN":"爸，爸爸……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아샤! 저 자는 당신이 생각하는 아버지가 아닙니다!","JPN":"アーシャ！　あれはあなたが探していた父親ではありません！","ENG":"Asha! That man is not the father you think he is!","TWN":"阿莎！那個人不是你爸爸！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아샤! 정신 차리세요!","JPN":"アーシャ！　しっかりしてください！","ENG":"Asha! Come to your senses!","TWN":"阿莎！清醒點！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"무슨 짓을 한 거죠?","JPN":"何をしたのですか？","ENG":"What did you do?","TWN":"你對她做了什麼？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저 자는 아디트야를 따르던 불순물입니다.","JPN":"その者はアーディティヤに従っていた不純物です。","ENG":"She is an impurity that used to follow Aditya.","TWN":"她只不過是追隨阿迪亞的雜質。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아디트야를 꾀어내기 위해 삼켰지만, 흥미로운 걸 갖고 있더군요.","JPN":"アーディティヤをおびき寄せるために飲み込みましたが、どうやら興味深いものを持っているようで。","ENG":"I had swallowed her to lure Aditya here, but it seems that she had something interesting in her possession.","TWN":"吞下她是為了引誘阿迪亞來這裡，不過我現在覺得她很有趣。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그래서, 불순물에게 아주 작은 기회를 주기로 했습니다.","JPN":"それで、不純物にほんの少しのチャンスを与えることにしました。","ENG":"So, I have decided to give the impurity a very small chance.","TWN":"所以我決定給這個雜質一個小小的機會。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"저 자는 지금 저와 함께 과거를 돌아보며 선택의 기로에 놓여 있겠죠.","JPN":"その者は今私とともに過去を振り返りながら、選択の岐路にいることでしょう。","ENG":"She will now probably be faced with a choice while looking back on the past with me.","TWN":"她現在應該是和我一起沉浸在過去的記憶裡，站在選擇的十字路口。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리를 받아들이고 더 나아갈지, 아니면 영원한 거짓 속에서 잠들지.","JPN":"私たちを受け入れて前に進むか、それとも永遠たる偽りの中で眠りにつくか。","ENG":"Whether she will accept us and move on, or sleep in eternal lies.","TWN":"是選擇接受然後繼續前進，還是一直沉睡在永恆的謊言裡……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"더 이상 그분의 명예를 더럽히지 마시죠.","JPN":"もうあの人の名誉を汚すのはやめて。","ENG":"Do not tarnish his honor any further.","TWN":"不要汙名化他了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"당신이 무슨 짓을 하더라도, 당신은 라비가 될 수 없습니다.","JPN":"あなたが何をしようとも、あなたはラビにはなれません。","ENG":"Whatever you do, you will never become Ravi.","TWN":"無論你做什麼，你都無法成為拉維。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"제가 라비입니다. 라비의 모습, 라비의 기억, 라비의 모든 것을 갖고 있는 제가요.","JPN":"私がラビなのです。ラビの姿、ラビの記憶、ラビのすべてを持っている私こそが。","ENG":"I am Ravi. I have his appearance, his memories, and everything else.","TWN":"我就是拉維。我擁有拉維的外貌、拉維的記憶，以及拉維的一切。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너같이 미지근하고, 속내가 복잡한 녀석은 불꽃의 이름을 받을 자격이 없다.","JPN":"君のような生ぬるく、いけ好かない下心を持っているやつに炎の名を受け継ぐ資格などない。","ENG":"Someone who is as lukewarm and complicated as you does not deserve the name of the flame.","TWN":"像你這樣優柔寡斷、心思複雜的傢伙，不配擁有火焰之名。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"넌 아합이다. 너에게 딱 어울리는 이름이지.","JPN":"君はアハブだ。それが君に相応しい名前だ。","ENG":"You are Ahab. That's a name that befits you.","TWN":"你是亞哈，這個名字非常適合你。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너는 그자처럼 불꽃을 피우지 못해. 나는 그 이름을 허락하지 않는다.","JPN":"君は彼のような炎を起こすことはできない。私はその名前を許可しない。","ENG":"You cannot ignite a flame like him, and I have never allowed that name to you.","TWN":"你無法像他那樣燃起火焰，我不允許你使用那個名字。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}}]`);export{e as default};